import yfinance as yf
import json
from datetime import datetime

stocks = ['AAPL', 'NVDA', 'META', 'GOOGL', 'MSFT', 'TSLA']
results = {}

for sym in stocks:
    try:
        t = yf.Ticker(sym)
        info = t.info

        price = info.get('regularMarketPrice') or info.get('currentPrice')
        trailing_pe = info.get('trailingPE')
        forward_pe = info.get('forwardPE')
        peg_ratio = info.get('pegRatio')
        shares = info.get('sharesOutstanding', 0)

        # Get 5Y historical year-end prices
        hist = t.history(period='5y')
        yearly_closes = hist.resample('YE').last()['Close']

        # Get annual net income
        try:
            financials = t.financials
            if financials is not None and 'Net Income' in financials.index:
                ni_series = financials.loc['Net Income']
                # Most recent 5 years of net income
                ni_by_year = {}
                for col in ni_series.columns[:5]:
                    ni_by_year[col.year] = ni_series[col]
            else:
                ni_by_year = {}
        except Exception as e:
            ni_by_year = {}

        results[sym] = {
            'price': price,
            'trailing_pe': trailing_pe,
            'forward_pe': forward_pe,
            'peg_ratio': peg_ratio,
            'shares': shares,
            'yearly_closes': {str(k): v for k, v in yearly_closes.items()},
            'net_income_by_year': {str(k): v for k, v in ni_by_year.items()},
        }
    except Exception as e:
        results[sym] = {'error': str(e)}

print(json.dumps(results, default=str))
